sql:
SELECT COUNT(candidate_id) AS number_of_applicants
FROM applications
WHERE posting_id = 0;

SELECT DISTINCT dp.department_name
FROM job_postings j
JOIN departments dp ON j.department_id = dp.department_id;

SELECT COUNT(application_id) AS total_applications
FROM applications
WHERE application_date LIKE '2023-05-%';

SELECT COUNT(candidate_id) AS confirmed_candidates_count
FROM selections
WHERE status = 'confirmed';

SELECT COUNT(candidate_id) AS number_of_passing_candidates
FROM examination_results
WHERE status = 'pass';

SELECT cat_no, COUNT(posting_id) AS number_of_postings
FROM job_postings
GROUP BY cat_no;

SELECT department_name
FROM departments
WHERE department_id > 10;

SELECT department_name
FROM departments
WHERE department_id = 1;

SELECT j.name_of_post, e.exam_date, e.exam_location
FROM job_postings j
JOIN examinations e ON j.posting_id = e.posting_id;

external_knowledge:
- "Position under the spotlight" refers to a specific job posting (posting_id = 1);
- "Golden trio" refers to the top three candidates;
- "Shone the brightest" metaphorically refers to the candidates who obtained the highest scores.

